const { Manifold, CrossSection } = api;

// === BODY ===
// Bottom sphere: r=10, centered at z=10
const bottom = api.label(Manifold.sphere(10).translate([0, 0, 10]), 'bottom');

// Middle sphere: r=7, sits on top of bottom (z=10+10+7=27)
const middle = api.label(Manifold.sphere(7).translate([0, 0, 27]), 'middle');

// Top (head) sphere: r=5, sits on top of middle (z=27+7+5=39)
const head = api.label(Manifold.sphere(5).translate([0, 0, 39]), 'head');

// === CARROT NOSE ===
// Small orange cone pointing forward (+Y direction)
// Profile: right triangle cross-section, tip pointing forward
// Revolve around Y to get a cone, place on front of head
// Cone: base r=0.8, height=3, pointing in +Y direction
// Nose sits at center of head sphere face at y ~ -5 (front)
const noseProfile = CrossSection.circle(0.8, 12);
const noseCone = api.label(
  noseProfile.revolve(12).rotate([90, 0, 0]).translate([0, -6.5, 39]),
  'nose'
);

// === EYES ===
// Two small spheres above the nose on the head
const eyeL = api.label(
  Manifold.sphere(0.7).translate([-1.8, -4.5, 41.5]),
  'eyeL'
);
const eyeR = api.label(
  Manifold.sphere(0.7).translate([1.8, -4.5, 41.5]),
  'eyeR'
);

// === BUTTONS (3 on middle sphere front) ===
// Evenly spaced down the front of middle sphere
const btn1 = api.label(
  Manifold.sphere(0.7).translate([0, -6.8, 29]),
  'btn1'
);
const btn2 = api.label(
  Manifold.sphere(0.7).translate([0, -6.6, 27]),
  'btn2'
);
const btn3 = api.label(
  Manifold.sphere(0.7).translate([0, -6.8, 25]),
  'btn3'
);

// === ARMS ===
// Thin cylinders sticking out sideways from middle sphere
// Left arm: pointing in -X direction, right arm: +X
const armL = api.label(
  Manifold.cylinder(8, 0.6, 0.4, 12)
    .rotate([0, 90, 0])
    .translate([-6, 0, 27]),
  'armL'
);
const armR = api.label(
  Manifold.cylinder(8, 0.6, 0.4, 12)
    .rotate([0, -90, 0])
    .translate([6, 0, 27]),
  'armR'
);

// === TOP HAT ===
// Brim: flat disk, r=4.5, h=0.8
// Crown: cylinder r=3, h=6
const hatBrim = Manifold.cylinder(0.8, 4.5, 4.5).translate([0, 0, 43.5]);
const hatCrown = Manifold.cylinder(6, 3, 3).translate([0, 0, 44.3]);
const hat = api.label(hatBrim.add(hatCrown), 'hat');

// === ASSEMBLE ===
const snowman = bottom
  .add(middle)
  .add(head)
  .add(noseCone)
  .add(eyeL)
  .add(eyeR)
  .add(btn1)
  .add(btn2)
  .add(btn3)
  .add(armL)
  .add(armR)
  .add(hat);

return snowman;

