// Cone: tip at -Y, base radius 0.8, length 3.5
// Use cylinder(h, rBase, rTip) then rotate to point forward (-Y)
// cylinder along Z: base at z=0, tip at z=h
// rotate([90,0,0]) -> along -Y axis (Z becomes -Y)
// Place base flush with head surface: head center at z=37, front face at y=-5
// Nose base starts at y=-4.5, tip at y=-4.5-3.5=-8
const nose = api.label(
  Manifold.cylinder(3.5, 0.85, 0, 12)
    .rotate([90, 0, 0])
    .translate([0, -4.5, 37]),
  'nose'
);

// === EYES ===
// Two small dark spheres on front-upper of head
const eyeL = api.label(
  Manifold.sphere(0.65).translate([-1.7, -4.3, 39.5]),
  'eyeL'
);
const eyeR = api.label(
  Manifold.sphere(0.65).translate([1.7, -4.3, 39.5]),
  'eyeR'
);

// === BUTTONS (3 on front of middle sphere) ===
const btn1 = api.label(
  Manifold.sphere(0.65).translate([0, -6.7, 28.5]),
  'btn1'
);
const btn2 = api.label(
  Manifold.sphere(0.65).translate([0, -6.8, 26]),
  'btn2'
);
const btn3 = api.label(
  Manifold.sphere(0.65).translate([0, -6.7, 23.5]),
  'btn3'
);

// === ARMS ===
// Thin cylinders protruding symmetrically from middle sphere sides
// Left arm: -X direction, right arm: +X direction
// rotate([0,-90,0]) -> cylinder goes along -X, base x=0, tip x=-h
// translate([3,0,26]): base at x=3 (inside sphere), tip at x=3-14=-11
const armL = api.label(
  Manifold.cylinder(14, 0.65, 0.4, 12)
    .rotate([0, -90, 0])
    .translate([3, 0, 26]),
  'armL'
);
// rotate([0,90,0]) -> goes along +X
// translate([-3,0,26]): base at x=-3 (inside sphere), tip at x=-3+14=11
const armR = api.label(
  Manifold.cylinder(14, 0.65, 0.4, 12)
    .rotate([0, 90, 0])
    .translate([-3, 0, 26]),
  'armR'
);

// === TOP HAT ===
// Hat brim: wide flat disk at head top
// Head top at z = 37+5 = 42
// Brim: r=4.5, h=0.8, sits at z=41.5
const hatBrim = Manifold.cylinder(0.8, 4.5, 4.5).translate([0, 0, 41.5]);
// Crown: r=3, h=6.5, sits on brim
const hatCrown = Manifold.cylinder(6.5, 3, 3).translate([0, 0, 42.3]);
const hat = api.label(hatBrim.add(hatCrown), 'hat');

// === ASSEMBLE ===
return bottom
  .add(middle)
  .add(head)
  .add(nose)
  .add(eyeL)
  .add(eyeR)
  .add(btn1)
  .add(btn2)
  .add(btn3)
  .add(armL)
  .add(armR)
  .add(hat);

